import re

content = open("llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp").read()

def inject(content):
    idx = content.find("const WithOverflowInst *WO;")
    if idx == -1: return content

    code_to_add = """
  // umul.with.overflow(X, C1) > C2 -> X > C2 / C1
  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
                                        m_WithOverflowInst(WO), m_Value(WOV))),
                                    m_Value(Ov)),
                       m_OneUse(m_ICmp(Pred, m_ExtractValue<0>(m_Deferred(WOV)),
                                       m_APInt(C2))))) &&
      WO->getBinaryOp() == Instruction::Mul && !WO->isSigned() &&
      match(WO->getRHS(), m_APInt(C1)) && !C1->isZero() &&
      (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_UGE || Pred == ICmpInst::ICMP_EQ)) {
    // For umul.with.overflow, if we check ov | res > C2
    if (Pred == ICmpInst::ICMP_UGT) {
      APInt NewC = C2->udiv(*C1);
      return new ICmpInst(ICmpInst::ICMP_UGT, WO->getLHS(),
                          ConstantInt::get(WO->getLHS()->getType(), NewC));
    }
  }
